import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void basic() {
        char[] s = {'h', 'e', 'l', 'l', 'o'};
        new Solution().reverseString(s);
        assertArrayEquals(new char[]{'o', 'l', 'l', 'e', 'h'}, s);
    }

    @Test
    void evenLength() {
        char[] s = {'a', 'b', 'c', 'd'};
        new Solution().reverseString(s);
        assertArrayEquals(new char[]{'d', 'c', 'b', 'a'}, s);
    }

    @Test
    void single() {
        char[] s = {'z'};
        new Solution().reverseString(s);
        assertArrayEquals(new char[]{'z'}, s);
    }

    @Test
    void empty() {
        char[] s = {};
        new Solution().reverseString(s);
        assertArrayEquals(new char[]{}, s);
    }

    @Test
    void palindrome() {
        // reversing a palindrome leaves it unchanged
        char[] s = {'r', 'a', 'c', 'e', 'c', 'a', 'r'};
        new Solution().reverseString(s);
        assertArrayEquals(new char[]{'r', 'a', 'c', 'e', 'c', 'a', 'r'}, s);
    }

    @Test
    void twoChars() {
        char[] s = {'x', 'y'};
        new Solution().reverseString(s);
        assertArrayEquals(new char[]{'y', 'x'}, s);
    }
}
